parameters.jsCode:
const originalBody = $('Webhook - Réception Document').first().json.body;

const extractedText = $input.all()
  .flatMap(item => item.json.ParsedResults || [])
  .map(r => r.ParsedText)
  .join('\n');

return [{ json: { 
  extracted_text: extractedText, 
  patient_id: originalBody.patient_id, 
  patient_age: originalBody.patient_age || null, 
  doc_type_hint: originalBody.doc_type_hint || 'inconnu' 
} }];

const agentOutput = $input.first().json.output;
let parsed;
try {
  const clean = agentOutput.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {
  parsed = { error: true, raw: agentOutput };
}
const webhook = $('Webhook - Réception Document').first().json.body;
const data = $input.first().json;
return [{
  json: {
    ...parsed,
    analysis_id: 'A-' + Math.random().toString(36).substr(2, 8).toUpperCase(),
    patient_id: webhook.patient_id,
    patient_name: webhook.patient_name || null,
    patient_age: webhook.patient_age || null,
    patient_sex: webhook.patient_sex || null,
    doc_filename: webhook.filename || 'document.pdf',
    extracted_text: data.extracted_text || data.text || null,
    timestamp: new Date().toISOString()
  }
}];

